import Foundation

let numbers = Array(0...9)

// Array slicing with ranges
print("Full array: \(numbers)")
print("First 3: \(numbers[0..<3])")
print("From index 7: \(numbers[7...])")
print("Up to index 4: \(numbers[...4])")

// Range as condition
let age = 25
switch age {
case 0..<13:
    print("Child")
case 13..<20:
    print("Teen")
case 20..<65:
    print("Adult")
case 65...:
    print("Senior")
default:
    break
}

// Creating and checking ranges
let gradeRange = 70...100
let score = 88
if gradeRange.contains(score) {
    print("\(score) is a passing score")
} else {
    print("\(score) needs improvement")
}
